-- ── Flag-array bases + lengths (client.py DATA_LOCATIONS, WRAM) ────────────────
local ARR = {
  -- code 1=EventFlag 2=Missable 3=Hidden 4=Rod 5=DexSanityFlag
  [1] = { base = 0x1735, len = 0x140 },   -- EventFlag
  [2] = { base = 0x161A, len = 0x20  },   -- Missable
  [3] = { base = 0x16DE, len = 0x0E  },   -- Hidden
  [4] = { base = 0x1716, len = 0x01  },   -- Rod
  [5] = { base = 0x1A71, len = 19    },   -- DexSanityFlag
}

-- ── Gate addresses (client.game_watcher) ──────────────────────────────────────
local GAME_STATUS_ADDR = 0x1A84    -- must be 0x2A or 0xAC once a save is loaded
local RESET_BASE       = 0x0100    -- 4 bytes; 0x7FFFFFFF (\xff\xff\xff\x7f) = pre-load
local CRASH1_ADDR      = 0x1731    -- 2 bytes: b0 & 0xF0 == 0 AND b1 == 0
local CRASH2_ADDR      = 0x1617    -- 1 byte: == 0
local CRASH3_ADDR      = 0x1A70    -- 1 byte: <= 10
local CRASH4_ADDR      = 0x16DD    -- 1 byte: <= 3

