-- ── State ─────────────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil     -- cached ROM-title result
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[pokemon_rb] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8 = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_u8(addr, domain)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, addr)            -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

local POW2 = { [0]=1, 2, 4, 8, 16, 32, 64, 128 }

-- ── ROM identity: mirror client.validate_rom (GB header game title) ───────────
local function title_matches(target)
  for i = 1, #target do
    local b = read_u8(ROM_TITLE_ADDR + i - 1, ROM)
    if b == nil then return nil end             -- not readable yet; retry next poll
    if b ~= string.byte(target, i) then return false end
  end
  return true
end

local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local red = title_matches(ROM_TITLE_RED)
  if red == nil then return false end           -- ROM domain not ready; retry
  if red then rom_ok = true; log("ROM verified (POKEMON RED)"); return true end
  local blue = title_matches(ROM_TITLE_BLUE)
  if blue == nil then return false end
  if blue then rom_ok = true; log("ROM verified (POKEMON BLUE)"); return true end
  rom_ok = false
  log("non-Pokémon R/B ROM (header title mismatch) — detection idle")
  return false
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- ── Flag arrays (read once per poll) ──────────────────────────────────────────
-- arrays[arr_code][byte] = value. Each array refreshed fully each poll, exactly
-- like client.game_watcher reads the whole DATA_LOCATIONS block per frame.
local arrays = { [1]={}, [2]={}, [3]={}, [4]={}, [5]={} }

local function refresh_arrays()
  for code, info in pairs(ARR) do
    local a = arrays[code]
    for i = 0, info.len - 1 do
      a[i] = read_u8(info.base + i, WRAM)
    end
  end
end

local function arr_bit(arr_code, byte, bit)
  local a = arrays[arr_code]
  local v = a and a[byte]
  if v == nil then return false end
  return bit_and(v, POW2[bit]) ~= 0
end

-- packed -> arr, byte, bit
local function unpack_flag(packed)
  local arr  = math.floor(packed / 1000000)
  local rest = packed - arr * 1000000
  local byte = math.floor(rest / 100)
  local bit  = rest - byte * 100
  return arr, byte, bit
end

-- ── Detection gate (client.game_watcher: in-game AND not crashed) ─────────────
local function in_game()
  -- Pre-load guards: GameStatus 0, or ResetCheck == 0x7FFFFFFF (\xff\xff\xff\x7f)
  local status = read_u8(GAME_STATUS_ADDR, WRAM)
  if status == nil or status == 0 then return false end
  local r0 = read_u8(RESET_BASE + 0, WRAM)
  local r1 = read_u8(RESET_BASE + 1, WRAM)
  local r2 = read_u8(RESET_BASE + 2, WRAM)
  local r3 = read_u8(RESET_BASE + 3, WRAM)
  if r0 == 0xFF and r1 == 0xFF and r2 == 0xFF and r3 == 0x7F then return false end

  -- Crash guards: GameStatus must be 0x2A or 0xAC, and the four sentinels sane.
  if status ~= 0x2A and status ~= 0xAC then return false end
  local c1a = read_u8(CRASH1_ADDR + 0, WRAM)
  local c1b = read_u8(CRASH1_ADDR + 1, WRAM)
  if c1a == nil or c1b == nil then return false end
  if bit_and(c1a, 0xF0) ~= 0 or c1b ~= 0 then return false end
  local c2 = read_u8(CRASH2_ADDR, WRAM)
  if c2 == nil or c2 ~= 0 then return false end
  local c3 = read_u8(CRASH3_ADDR, WRAM)
  if c3 == nil or c3 > 10 then return false end
  local c4 = read_u8(CRASH4_ADDR, WRAM)
  if c4 == nil or c4 > 3 then return false end
  return true
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0
  for _ in pairs(LOC) do n = n + 1 end
  for _ in pairs(LOC_LIST) do n = n + 1 end
  log("ready: " .. n .. " location flags")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not in_game() then return new end
  refresh_arrays()
  -- single-flag locations
  for ap_id, packed in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) then
      local arr, byte, bit = unpack_flag(packed)
      if arr_bit(arr, byte, bit) then
        reported[ap_id] = true
        new[#new + 1] = ap_id
      end
    end
  end
  -- "list" locations: EventFlag bit AND Missable bit (arr 1 and arr 2)
  for ap_id, q in pairs(LOC_LIST) do
    if not reported[ap_id] and wanted(ap_id) then
      if arr_bit(1, q[1], q[2]) and arr_bit(2, q[3], q[4]) then
        reported[ap_id] = true
        new[#new + 1] = ap_id
      end
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  refresh_arrays()
  return arr_bit(1, GOAL_EVENT_BYTE, GOAL_EVENT_BIT)
end

-- Remote multiworld items: see the file header. items_handling = 0b001 means the
-- server only sends THIS slot's own items and the patched game grants its locally
-- found items itself, so solo play and check reporting work fully. Applying REMOTE
-- items is the client's guarded APItem-byte WRAM write (WRAM 0x00FF, gated on the
-- save's ItemIndex at 0x1A6E and the byte being 0); that is deferred until it can
-- be confirmed in-emulator. No-op (never a wrong write) until then.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
